import{_ as b,o as e,c as a,j as p,a as t,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"魔法战队下属 烈焰巨兽","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/2.改造与功法/改造/4.综合类/魔法战队/魔法战队下属 烈焰巨兽.md","filePath":"4.资源分区/2.改造与功法/改造/4.综合类/魔法战队/魔法战队下属 烈焰巨兽.md"}'),s={name:"4.资源分区/2.改造与功法/改造/4.综合类/魔法战队/魔法战队下属 烈焰巨兽.md"};function _(o,r,d,l,i,c){return e(),a("div",null,[...r[0]||(r[0]=[p("h1",{id:"魔法战队下属-烈焰巨兽",tabindex:"-1"},[t("魔法战队下属 烈焰巨兽 "),p("a",{class:"header-anchor",href:"#魔法战队下属-烈焰巨兽","aria-label":'Permalink to "魔法战队下属 烈焰巨兽"'},"​")],-1),p("table",{class:"bannerparthead"},[p("tbody",null,[p("tr",{id:"hdr"},[p("td",{class:"runninghead",nowrap:""},"TMD：新世短歌035")])])],-1),n('<h1 id="魔法战队下属-烈焰巨兽-1" tabindex="-1">魔法战队下属 烈焰巨兽 <a class="header-anchor" href="#魔法战队下属-烈焰巨兽-1" aria-label="Permalink to &quot;魔法战队下属 烈焰巨兽&quot;">​</a></h1><p>【魔法战队下属装备】<br> 魔法战队-烈焰巨兽<br> “烈焰巨兽是我少数在物理性质上还原能量攻击所进行的尝试之一。虽然事实证明那些能量和物理上的表现仅有一定程度的关联……不过，只要不是在市区内，这些装甲的作用可以称之为高效。”</p><p>【D级“烈焰巨兽”动力盔甲】</p><p>代号：火神<br> 分类：重甲<br> 基本属性：盔甲防御4/4，盔甲减值3<br> 特殊属性：无<br> 描述：火神是一件大型外骨骼动力装甲，其外观以深红色为主，装甲厚重而庞大。武装放射出的高热等离子流能够有效打击重护甲单位。<br> 外置装备：【火神炮】【等离子装置】</p><p>【火神炮】：火神炮视为一件喷火器类武器，使用【敏捷属性+射击+专业：喷火器+辅助专业：弹道学+武器伤害+其他加值（若有）】进行攻击，在着装盔甲时会同步被你持有。</p><p>火神炮的武器伤害为5L，武器体积3+1（附带等离子装置），伤害类型为火焰，具有【高速2】（已计入远程武器自带的高速），【破甲2】，【无限子弹】，【双手】，速射等级【短点射】，射程45米。</p><p>【等离子装置】：等离子装置会使你在使用火神炮进行攻击时，攻击附带1点不可豁免的燃烧不良点数；火神炮需要在启动等离子装置后才能使用，你需要消费一个移动动作才能启动等离子装置，使等火神炮维持运行一场景。</p><p>代号：熔岩<br> 分类：重甲<br> 基本属性：盔甲防御4/4，盔甲减值3<br> 特殊属性：无<br> 描述：熔岩是一件大型外骨骼动力装甲，其外观以深红色为主，装甲厚重而庞大，储存着大量燃料。由于武装喷射出的火焰可以轻而易举的让一片地区化作火海，在市区内禁止使用。<br> 外置装备：【岩浆放射器】【燃料罐】</p><p>【岩浆放射器】：岩浆放射器视为一件喷火器类武器，使用【敏捷属性+射击+专业：喷火器+辅助专业：弹道学+武器伤害+其他加值（若有）】进行攻击，在着装盔甲时会同步被你持有。</p><p>岩浆放射器的武器伤害为2L，武器体积3+1（附带燃料罐），伤害类型为火焰，具有【高速2】（已计入远程武器自带的高速），【破甲2】，【无限子弹】，【双手】，速射等级【短点射】，射程45米。</p><p>岩浆放射器可以对前方直线射程距离的所有敌对目标进行攻击，视为范围伤害，目标正常进行防御。</p><p>【燃料罐】：燃料罐会使你在使用火神炮进行攻击时，攻击附带2点标准豁免的燃烧不良点数；岩浆放射器需要在填装燃料罐才能使用，你需要消费一个移动动作才能填装燃料罐，使岩浆放射器维持运行一场景；由于燃料罐的存在，你获得【物理易伤1】。</p><p>代号：炽热<br> 分类：重甲<br> 基本属性：盔甲防御4/4，盔甲减值3<br> 特殊属性：无<br> 描述：炽热是一件大型外骨骼动力装甲，其外观以深红色为主，装甲厚重而庞大。炽热应用了先进的热传导技术，通过吸收热能的方式填充武装。<br> 外置装备：【连发火弹】【聚热装置】</p><p>【连发火弹】：连发火弹一件喷火器类武器，使用【敏捷属性+射击+专业：喷火器+辅助专业：弹道学+武器伤害+其他加值（若有）】进行攻击，在着装盔甲时会同步被你持有。</p><p>连发火弹的武器伤害为5L，武器体积3+1（附带聚热装置），伤害类型为火焰，具有【高速2】（已计入远程武器自带的高速），【破甲2】，【无限子弹】，【双手】，速射等级【连射】，射程45米。</p><p>【聚热装置】：聚热装置会使你在使用火神炮进行攻击时，攻击附带2点标准豁免的燃烧不良点数；连发火弹需要在启动聚热装置后才能使用，你需要消费一个移动动作才能启动聚热装置，使连发火弹维持运行一场景；聚热装置会为你提供【火焰能量抗力1】，若你因此抵消了至少1点火焰能量伤害，则连发火弹在该场景下的武器伤害提升1L。</p><p>升级（D+500）：烈焰巨兽下属动力装甲的武器射程提升至100米，如同购买一项D级技艺一样处理，正常提供自由属性。无论你选择了烈焰巨兽下属哪一个类型的动力装甲，都可以购买这一升级。</p><p>【C级“烈焰巨兽”动力盔甲】</p><p>代号：火神<br> 分类：重甲<br> 基本属性：盔甲防御12/12，盔甲减值3<br> 特殊属性：无<br> 描述：火神是一件大型外骨骼动力装甲，其外观以深红色为主，装甲厚重而庞大。武装放射出的高热等离子流能够有效打击重护甲单位。<br> 外置装备：【火神炮】【等离子装置】</p><p>【火神炮】：火神炮视为一件喷火器类武器，使用【敏捷属性+射击+专业：喷火器+辅助专业：弹道学+武器伤害+其他加值（若有）】进行攻击，在着装盔甲时会同步被你持有。</p><p>火神炮的武器伤害为10L，武器体积3+1（附带等离子装置），伤害类型为火焰，具有【高速2】（已计入远程武器自带的高速），【破甲2】，【无限子弹】，【双手】，速射等级【短点射】，射程45米。</p><p>【等离子装置】：等离子装置会使你在使用火神炮进行攻击时，攻击附带2点不可豁免的燃烧不良点数；火神炮需要在启动等离子装置后才能使用，因为技术迭代的缘故，现在你只需要消费一个花招动作并消费2点核能即可启动等离子装置，使火神炮维持运行一场景。</p><p>代号：熔岩<br> 分类：重甲<br> 基本属性：盔甲防御12/12，盔甲减值3<br> 特殊属性：无<br> 描述：熔岩是一件大型外骨骼动力装甲，其外观以深红色为主，装甲厚重而庞大，储存着大量燃料。由于武装喷射出的火焰可以轻而易举的让一片地区化作火海，在市区内禁止使用。<br> 外置装备：【岩浆放射器】【燃料罐】</p><p>【岩浆放射器】：岩浆放射器视为一件喷火器类武器，使用【敏捷属性+射击+专业：喷火器+辅助专业：弹道学+武器伤害+其他加值（若有）】进行攻击，在着装盔甲时会同步被你持有。</p><p>岩浆放射器的武器伤害为11L，武器体积3+1（附带燃料罐），伤害类型为火焰，具有【高速2】（已计入远程武器自带的高速），【破甲2】，【无限子弹】，【双手】，速射等级【短点射】，射程45米。</p><p>岩浆放射器可以对前方扇形射程范围的所有敌对目标进行攻击，目标正常进行防御。</p><p>【燃料罐】：燃料罐会使你在使用火神炮进行攻击时，攻击附带2点标准豁免的燃烧不良点数；岩浆放射器需要在填装燃料罐才能使用，因为技术迭代的缘故，现在你只需要消费一个自由动作即可启动岩浆放射器，使岩浆放射器维持运行一场景。</p><p>代号：炽热<br> 分类：重甲<br> 基本属性：盔甲防御12/12，盔甲减值3<br> 特殊属性：无<br> 描述：炽热是一件大型外骨骼动力装甲，其外观以深红色为主，装甲厚重而庞大。炽热应用了先进的热传导技术，通过吸收热能的方式填充武装。<br> 外置装备：【连发火弹】【聚热装置】</p><p>【连发火弹】：连发火弹一件喷火器类武器，使用【敏捷属性+射击+专业：喷火器+辅助专业：弹道学+武器伤害+其他加值（若有）】进行攻击，在着装盔甲时会同步被你持有。</p><p>连发火弹的武器伤害为11L，武器体积3+1（附带聚热装置），伤害类型为火焰，具有【高速2】（已计入远程武器自带的高速），【破甲2】，【无限子弹】，【双手】，速射等级【连射】，攻击额外获得1个附加成功数，射程45米。</p><p>【聚热装置】：聚热装置会为你提供【火焰能量抗力3】；聚热装置会使你在使用火神炮进行攻击时，攻击附带2点标准豁免的燃烧不良点数。<br> 连发火弹需要在启动聚热装置后才能使用，因为技术迭代的缘故，现在你只需要消费一个自由动作即可启动聚热装置，使连发火弹维持运行一场景。</p><p>【B级“烈焰巨兽”动力盔甲】</p><p>代号：火神<br> 分类：重甲<br> 基本属性：盔甲防御19/19，盔甲减值3<br> 特殊属性：无<br> 描述：火神是一件大型外骨骼动力装甲，其外观以深红色为主，装甲厚重而庞大。武装放射出的高热等离子流能够有效打击重护甲单位。<br> 外置装备：【火神炮】【等离子装置】</p><p>【火神炮】：火神炮视为一件喷火器类武器，使用【敏捷属性+射击+专业：喷火器+辅助专业：弹道学+武器伤害+其他加值（若有）】进行攻击，在着装盔甲时会同步被你持有。</p><p>火神炮的武器伤害为18L，武器体积3+1（附带等离子装置），伤害类型为火焰，具有【高速2】（已计入远程武器自带的高速），【破甲2】，【无限子弹】，【双手】，速射等级【短点射】，射程45米。</p><p>使用火神炮进行的攻击，攻击加骰提升1级处理（上限8加骰）。</p><p>【等离子装置】：等离子装置会使你在使用火神炮进行攻击时，攻击附带3点不可豁免的燃烧不良点数；火神炮需要在启动等离子装置后才能使用，因为技术迭代的缘故，现在你只需要消费一个花招动作并消费2点核能即可启动等离子装置，使火神炮维持运行一场景。</p><p>代号：熔岩<br> 分类：重甲<br> 基本属性：盔甲防御19/19，盔甲减值3<br> 特殊属性：无<br> 描述：熔岩是一件大型外骨骼动力装甲，其外观以深红色为主，装甲厚重而庞大，储存着大量燃料。由于武装喷射出的火焰可以轻而易举的让一片地区化作火海，在市区内禁止使用。<br> 外置装备：【岩浆放射器】【燃料罐】</p><p>【岩浆放射器】：岩浆放射器视为一件喷火器类武器，使用【敏捷属性+射击+专业：喷火器+辅助专业：弹道学+武器伤害+其他加值（若有）】进行攻击，在着装盔甲时会同步被你持有。</p><p>岩浆放射器的武器伤害为18L，武器体积3+1（附带燃料罐），伤害类型为火焰，具有【高速3】（已计入远程武器自带的高速），【破甲3】，【无限子弹】，【接触攻击】，【双手】，速射等级【长点射】，射程45米。</p><p>岩浆放射器可以对前方扇形射程范围的所有敌对目标进行攻击，目标正常进行防御。</p><p>【燃料罐】：燃料罐会使你在使用火神炮进行攻击时，攻击附带2点标准豁免的燃烧不良点数；岩浆放射器需要在填装燃料罐才能使用，因为技术迭代的缘故，现在你只需要消费一个自由动作即可启动岩浆放射器，使岩浆放射器维持运行一场景。</p><p>代号：炽热<br> 分类：重甲<br> 基本属性：盔甲防御19/19，盔甲减值3<br> 特殊属性：无<br> 描述：炽热是一件大型外骨骼动力装甲，其外观以深红色为主，装甲厚重而庞大。炽热应用了先进的热传导技术，通过吸收热能的方式填充武装。<br> 外置装备：【连发火弹】【聚热装置】</p><p>【连发火弹】：连发火弹一件喷火器类武器，使用【敏捷属性+射击+专业：喷火器+辅助专业：弹道学+武器伤害+其他加值（若有）】进行攻击，在着装盔甲时会同步被你持有。</p><p>连发火弹的武器伤害为18L，武器体积3+1（附带聚热装置），伤害类型为火焰，具有【高速2】（已计入远程武器自带的高速），【破甲2】，【无限子弹】，【湮灭】，【双手】，速射等级【连射】，攻击额外获得2个附加成功数，射程45米。</p><p>【聚热装置】：聚热装置会为你提供【火焰能量抗力3】；聚热装置会使你在使用火神炮进行攻击时，攻击附带2点标准豁免的燃烧不良点数。<br> 连发火弹需要在启动聚热装置后才能使用，因为技术迭代的缘故，现在你只需要消费一个自由动作即可启动聚热装置，使连发火弹维持运行一场景。</p><p>【A级“烈焰巨兽”动力盔甲】</p><p>代号：火神<br> 分类：重甲<br> 基本属性：盔甲防御28/28，基于盔甲2个防御附加，盔甲减值3<br> 特殊属性：无<br> 描述：火神是一件大型外骨骼动力装甲，其外观以深红色为主，装甲厚重而庞大。武装放射出的高热等离子流能够有效打击重护甲单位。<br> 外置装备：【火神炮】【等离子装置】</p><p>【火神炮】：火神炮视为一件喷火器类武器，使用【敏捷属性+射击+专业：喷火器+辅助专业：弹道学+武器伤害+其他加值（若有）】进行攻击，在着装盔甲时会同步被你持有。</p><p>火神炮的武器伤害为27L，额外获得2个攻击附加成功数，武器体积3+1（附带等离子装置），伤害类型为火焰，具有【高速2】（已计入远程武器自带的高速），【破甲2】，【无限子弹】，【双手】，速射等级【短点射】，射程45米。</p><p>使用火神炮进行的攻击，攻击加骰提升1级处理（上限8加骰）。</p><p>【等离子装置】：等离子装置会使你在使用火神炮进行攻击时，使被命中的目标进行反射豁免对抗伤害出目，失败则承受差值的燃烧不良点数，且至少造成1点燃烧不良点数（但可以被异常点数减少类能力正常抵消，也可以被正常移除）；每轮一次，你使用火神炮进行的攻击命中后会令其身上的燃烧不良点数产生【激爆】。</p><p>火神炮需要在启动等离子装置后才能使用，因为技术迭代的缘故，现在你只需要消费一个自由动作即可启动等离子装置，使火神炮维持运行一场景。</p><p>代号：熔岩<br> 分类：重甲<br> 基本属性：盔甲防御28/28，基于盔甲2个防御附加，盔甲减值3<br> 特殊属性：无<br> 描述：熔岩是一件大型外骨骼动力装甲，其外观以深红色为主，装甲厚重而庞大，储存着大量燃料。由于武装喷射出的火焰可以轻而易举的让一片地区化作火海，在市区内禁止使用。<br> 外置装备：【岩浆放射器】【燃料罐】</p><p>【岩浆放射器】：岩浆放射器视为一件喷火器类武器，使用【敏捷属性+射击+专业：喷火器+辅助专业：弹道学+武器伤害+其他加值（若有）】进行攻击，在着装盔甲时会同步被你持有。</p><p>岩浆放射器的武器伤害为27L，额外获得2个攻击附加成功数，武器体积3+1（附带燃料罐），伤害类型为火焰，具有【高速3】（已计入远程武器自带的高速），【破甲3】，【无限子弹】，【接触攻击】，【双手】，速射等级【长点射】，射程等同使用者的敏感范围。</p><p>岩浆放射器可以对前方扇形射程范围的所有敌对目标进行攻击，目标正常进行防御；岩浆放射器进行的攻击忽略闪避防御，这是一个A级环境来源效果的影响。</p><p>【燃料罐】：燃料罐会使你在使用火神炮进行攻击时，攻击附带2点标准豁免的燃烧不良点数；岩浆放射器需要在填装燃料罐才能使用，因为技术迭代的缘故，现在你只需要消费一个自由动作即可启动岩浆放射器，使岩浆放射器维持运行一场景。</p><p>代号：炽热<br> 分类：重甲<br> 基本属性：盔甲防御28/28，基于盔甲2个防御附加，盔甲减值3<br> 特殊属性：无<br> 描述：炽热是一件大型外骨骼动力装甲，其外观以深红色为主，装甲厚重而庞大。炽热应用了先进的热传导技术，通过吸收热能的方式填充武装。<br> 外置装备：【连发火弹】【聚热装置】</p><p>【连发火弹】：连发火弹一件喷火器类武器，使用【敏捷属性+射击+专业：喷火器+辅助专业：弹道学+武器伤害+其他加值（若有）】进行攻击，在着装盔甲时会同步被你持有。</p><p>连发火弹的武器伤害为27L，额外获得4个攻击附加成功数，武器体积3+1（附带聚热装置），伤害类型为火焰，具有【高速2】（已计入远程武器自带的高速），【破甲2】，【无限子弹】，【湮灭】，【双手】，速射等级【连射】。</p><p>你可以使连发火弹进行的攻击出目增加一半处理，每轮这一效果只会生效一次。</p><p>【聚热装置】：聚热装置会为你提供【火焰能量抗力3】，并且你减少受到的一半火焰伤害；聚热装置会使你在使用火神炮进行攻击时，攻击附带2点标准豁免的燃烧不良点数。<br> 连发火弹需要在启动聚热装置后才能使用，因为技术迭代的缘故，现在你只需要消费一个自由动作即可启动聚热装置，使连发火弹维持运行一场景。</p><p>【S级“烈焰巨兽”动力盔甲】<br> 待补充。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',66)])])}const L=b(s,[["render",_]]);export{f as __pageData,L as default};
